  'shaoxing/pen': ('Колыбель каллиграфии', 'Павильон Ланьтин, связанный с именем мастера Ван Сичжи, считается священным местом для всех любителей каллиграфии.'),
  'shaoxing/boat': ('Лодки «упэн»', 'Традиционные лодки с черным навесом, которыми управляют с помощью ног, являются классическим способом передвижения по каналам.'),
  'bengbu/shell': ('Жемчужный порт', 'Название города переводится как «устричная пристань», ведь когда-то он славился жемчугом из реки Хуайхэ.'),
  'bengbu/train': ('Железнодорожный узел Бэнбу', 'Город вырос вокруг станции, расположенной на пересечении важнейшей железнодорожной магистрали север-юг через реку Хуайхэ.'),
  'bengbu/river': ('Река Хуайхэ', 'Именно здесь протекает река, которая традиционно считается географической границей между севером и югом Китая.'),
  'bengbu/blossom': ('Весенние ярмарки', 'Каждую весну прибрежные парки города наполняются яркими красками цветочных ярмарок.'),
  'jiujiang/mountain': ('Гора Лушань', 'Туманные вершины горы Лушань, включенной в список объектов всемирного наследия ЮНЕСКО, веками вдохновляли китайских поэтов и художников.'),
  'jiujiang/tea': ('Чай Юньу', 'Чай «Облака и туманы», выращиваемый на склонах горы Лушань, считается одним из самых изысканных сортов в Китае.'),
  'jiujiang/lake': ('Озеро Поянху', 'Крупнейшее пресноводное озеро Китая служит местом зимовки для тысяч перелетных журавлей.'),
  'jiujiang/scroll': ('Город поэтов', 'На этих речных берегах когда-то черпали вдохновение и писали свои строки великие поэты Бай Цзюйи и Су Ши.'),
  'quanzhou/ship': ('Морской Шелковый путь', 'Цюаньчжоу, известный Марко Поло как Зейтун, был величайшим портом средневекового мира и сегодня охраняется ЮНЕСКО.'),
  'quanzhou/mosque': ('Мечеть Цинцзин', 'Эта каменная мечеть, построенная в 1009 году, является одной из старейших в Китае.'),
  'quanzhou/puppet': ('Театр марионеток', 'Искусство управления нитяными куклами в Цюаньчжоу — это древняя театральная традиция с тысячелетней историей.'),
  'quanzhou/tea': ('Чай Тегуаньинь', 'Знаменитый на весь мир улун «Железная бодхисаттва» родом из соседнего уезда Аньси.'),
  'shanghai/pearl': ('Телебашня «Восточная жемчужина»', 'Возвышающаяся над рекой Хуанпу башня со своими розовыми сферами стала настоящим символом современного Шанхая.'),
  'shanghai/bund': ('Набережная Вайтань', 'Историческая набережная с фасадами старинных отелей отражает былое величие Шанхая.'),
  'shanghai/garden': ('Сад Юйюань', 'Классический сад эпохи Мин с его скалами и прудами представляет собой тихий оазис в самом сердце мегаполиса.'),
  'shanghai/xlb': ('Сяолунбао', 'Паровые пельмени с горячим бульоном внутри — признанный шедевр шанхайского завтрака.'),
  'hangzhou/lake': ('Сиху', 'Это озеро с ивами, островками и арочными мостиками воспето в бесчисленных китайских поэтических произведениях.'),
  'hangzhou/tea': ('Чай Лунцзин', 'Выращенный на склонах вокруг озера, этот зеленый чай «Колодец дракона» считается самым знаменитым в Китае.'),
  'hangzhou/temple': ('Храм Линъинь', 'Храм «Прибежища души», которому уже 1700 лет, славится своими наскальными рельефами и гигантской статуей Будды.'),
  'hangzhou/silk': ('Город шелка', 'Ханчжоуский шелк, который ткут здесь уже тысячу лет, был главным богатством восточного конца Великого шелкового пути.'),
  'chongqing/hongya': ('Хунъядун', 'Этот комплекс домов на сваях, цепляющийся за скалу, по ночам сияет над рекой, словно сказочный дворец.'),
  'chongqing/hotpot': ('Чунцинский хого', 'Бурлящий острым маслом и пряным перцем, этот китайский самовар является огненной душой города на холмах.'),
  'chongqing/monorail': ('Чунцинский монорельс', 'Монорельсовая дорога, проходящая прямо сквозь жилой дом, стала визитной карточкой этого города, построенного на крутых склонах.'),
  'chongqing/river': ('Ущелья Янцзы', 'Круизные лайнеры отправляются отсюда, где город возвышается над местом слияния двух великих рек.'),
  'dalian/square': ('Площадь Синхай', 'Крупнейшая городская площадь в Азии, расположенная на побережье, служит местом проведения ярких фестивалей и шоу.'),
  'dalian/beach': ('Пляжи Даляня', 'Благодаря скалистым бухтам и прохладному лету Далянь считается любимым морским курортом северного Китая.'),
  'dalian/football': ('Футбольный город', 'Далянь называют «колыбелью футбола» Китая, ведь именно здесь зародились самые титулованные клубы страны.'),
  'dalian/seafood': ('Морепродукты', 'Гребешки, креветки и морские ежи из холодных вод Желтого моря — главное украшение столов в этом городе.'),
  'shenyang/palace': ('Мукденский дворец', 'Первая резиденция династии Цин, которую часто называют младшим братом пекинского Запретного города.'),
  'shenyang/tomb': ('Гробницы династии Цин', 'Восточная и Северная гробницы, окружающие город, являются монументальными мавзолеями основателей династии.'),
  'shenyang/factory': ('Колыбель индустрии', 'Здесь зародилась тяжелая промышленность Китая, а за обилие огромных заводов город прозвали «Восточным Руром».'),
  'shenyang/dumpling': ('Пельмени «Лаобянь»', 'Паровые пельмени «Лаобянь» с двухсотлетней историей — визитная карточка кухни северного Китая.'),
  'hefei/judge': ('Храм Бао-гуна', 'Храм посвящен легендарному судье Бао Чжэну, уроженцу этих мест, который стал символом честности и справедливости.'),
  'hefei/science': ('Научный центр Хэфэя', 'Технологический хаб, объединяющий ведущие университеты и научно-исследовательские лаборатории Китая.'),
  'hefei/lake': ('Озеро Чаоху', 'Одно из пяти крупнейших пресноводных озер Китая, знаменитое своими крабами и белой рыбой.'),
  'hefei/cake': ('Кунжутный пирог Лу', 'Сладкий кунжутный пирог — традиционное лакомство, история которого уходит корнями в древний Лучжоу.'),
  'foshan/wingchun': ('Вин-чунь', 'Фошань считается родиной боевого искусства вин-чунь, где оттачивали свое мастерство Ип Ман и Брюс Ли.'),
  'foshan/lion': ('Танец льва', 'Фошань — столица южного танца льва, где артисты в ярких костюмах совершают акробатические прыжки на столбах.'),
  'foshan/ceramic': ('Керамика Шивань', 'В местных печах с тысячелетней историей до сих пор создают знаменитые живые фигурки из керамики Шивань.'),
  'foshan/opera': ('Кантонская опера', 'Именно на этих землях сформировалось и достигло расцвета одно из самых любимых сценических искусств Южного Китая.'),
  'guiyang/pavilion': ('Павильон Цзясю', 'Трехъярусный павильон на реке Наньмин уже 400 лет является главным символом города.'),
  'guiyang/sourfish': ('Рыба в кислом супе', 'Рыба, томленая в остро-кислом бульоне на основе ферментированных томатов, — главное фирменное блюдо провинции Гуйчжоу.'),
  'guiyang/waterfall': ('Водопад Хуангошу', 'Один из крупнейших водопадов Азии низвергается с грохотом, создавая в брызгах воды яркие радуги.'),
  'guiyang/miao': ('Культура народа мяо', 'Праздники и вышивка народа мяо, чьи женщины носят массивные серебряные украшения, оживляют горные деревни региона.'),
  'changchun/film': ('Киногород Чанчунь', 'Здесь расположены студии, где зародился китайский кинематограф, за что город прозвали «Восточным Голливудом».'),
  'changchun/car': ('Автомобильная столица', 'Чанчунь считается автомобильной столицей Китая, ведь именно здесь с конвейера сошел первый отечественный автомобиль.'),
  'changchun/palace': ('Дворец марионеточного императора', 'Дворец, в котором жил последний император Китая, стал безмолвным свидетелем бурных исторических событий.'),
  'changchun/snow': ('Зимние снега', 'Долгими белыми зимами город сияет ледяными скульптурами и горнолыжными трассами.'),
  'xining/lake': ('Озеро Кукунор', 'Крупнейшее соленое озеро Китая славится желтыми полями рапса, которые окружают его летом.'),
  'xining/monastery': ('Монастырь Кумбум', 'Один из шести великих монастырей тибетского буддизма, известный своими скульптурами из масла яка.'),
  'xining/flower': ('Цветение рапса', 'В июле нагорье до самого горизонта покрывается золотистым ковром цветущего рапса.'),
  'xining/lamb': ('Яки и баранина', 'Тянутая лапша и шашлыки из баранины в традициях хуэйской и тибетской кухни — главные вкусы этого нагорья.'),
  'guilin/karst': ('Карстовые горы реки Ли', 'Известняковые пики, поднимающиеся из тумана, изображены на купюре в 20 юаней.'),
  'guilin/elephant': ('Гора Слоновий хобот', 'Скала в форме слона, опускающего хобот в реку, является любимым символом города.'),
  'guilin/terrace': ('Рисовые террасы Лунцзи', 'Террасы «Хребет дракона», опоясывающие склоны гор, представляют собой лестницу, созданную веками упорного труда.'),
  'guilin/osmanthus': ('Цветение османтуса', 'Название города означает «лес османтуса», и осенью он утопает в сладком аромате этих цветов.'),
  'wenzhou/merchant': ('Дух предпринимательства', 'Вэньчжоуских бизнесменов часто называют «китайскими евреями» за их умение выстраивать деловые сети по всему миру.'),
  'wenzhou/shoe': ('Обувь и кожа', 'Огромная доля кожаной обуви, производимой в мире, выпускается на фабриках этого города.'),
  'wenzhou/mountain': ('Горы Яньданшань', 'Эти горы, знаменитые своими водопадами и острыми пиками, называют «первыми горами у моря».'),
  'wenzhou/seafood': ('Морепродукты', 'Кальмары, гребешки и рыба из Восточно-Китайского моря составляют основу местного рациона.'),
  'tangshan/memorial': ('Мемориал землетрясения', 'Мемориальный парк, посвященный разрушительному землетрясению 1976 года, стал символом возрожденного города.'),
  'tangshan/coal': ('Уголь и сталь', 'Здесь были открыты первая в Китае современная угольная шахта и железная дорога, ставшие колыбелью национальной промышленности.'),
  'tangshan/ceramic': ('Таншаньский фарфор', 'Этот «северный город фарфора» славится своим изысканным костяным фарфором, который украшает столы по всему миру.'),
  'tangshan/lake': ('Парк Наньху', 'Живописный парк с озером, разбитый на месте старого угольного карьера, стал настоящими «зелеными легкими» города.'),
  'anshan/steel': ('Стальной город', 'Здесь был основан крупнейший в Китае металлургический комбинат, благодаря чему город получил статус «стальной столицы» страны.'),
  'anshan/jade': ('Сюяньский нефрит', 'В этом городе находится самая большая в мире нефритовая скульптура, а сам регион по праву считается нефритовой сокровищницей Китая.'),
  'anshan/mountain': ('Гора Цяньшань', '«Гора тысячи лотосов» с ее древними храмами и отвесными скалами считается одной из самых священных вершин на севере страны.'),
  'anshan/spring': ('Горячие источники Танганцзы', 'Целебные горячие источники, которые на протяжении тысячи лет привлекали даже китайских императоров.'),
  'linyi/market': ('Оптовый рынок', 'Крупнейший в Северном Китае оптовый торговый центр, откуда товары отправляются во все уголки страны.'),
  'linyi/brush': ('Мастер каллиграфии', 'Здесь родился «мудрец каллиграфии» Ван Сичжи, поэтому город по праву называют родиной китайской туши и кисти.'),
  'linyi/mountain': ('Гора Мэншань', 'Вторая по высоте гора провинции Шаньдун, известная своим чистейшим воздухом, водопадами и густыми лесами.'),
  'linyi/pancake': ('Блины Имын', 'Тонкие кукурузные блины «цзяньбин» являются традиционным и любимым блюдом жителей горных районов Имын.'),
  'cangzhou/lion': ('Железный лев', 'Огромная статуя железного льва, отлитая более тысячи лет назад, является главным символом и гордостью города.'),
  'cangzhou/martial': ('Боевые искусства', 'Цанчжоу считается «домом ушу», откуда вышли многие знаменитые мастера и школы боевых искусств.'),
  'cangzhou/canal': ('Великий канал', 'Через город проходит Великий канал Пекин — Ханчжоу, на берегах которого до сих пор сохранились старинные пристани.'),
  'cangzhou/jujube': ('Золотой зизифус', 'Сладкий «золотой» зизифус с тонкой кожицей по праву считается королем сухофруктов в этом регионе.'),
  'nantong/textile': ('Город текстиля', 'Наньтун считается столицей домашнего текстиля, а местный хлопок поставляется на рынки по всему миру.'),
  'nantong/mountain': ('Гора Ланшань', 'Эта священная гора с пятью вершинами, возвышающаяся в устье Янцзы, является местом паломничества и славится своими живописными видами.'),
  'nantong/kite': ('Поющие змеи баньяо', 'Традиционные воздушные змеи баньяо, оснащенные специальными свистками, — это старинный народный промысел города.'),
  'nantong/school': ('Колыбель современного образования', 'Именно здесь промышленник Чжан Цзянь основал первые в Китае современные школы и музей.'),
  'taizhou/opera': ('Мэй Ланьфан', 'Тайчжоу — родина легендарного мастера пекинской оперы Мэй Ланьфана.'),
  'taizhou/tea': ('Утреннее чаепитие', 'Завтрак, состоящий из паровых булочек и свежезаваренного чая, является важным городским ритуалом.'),
  'taizhou/boat': ('Фестиваль лодок в Циньтуне', 'Весной река оживает благодаря красочному фестивалю, во время которого сотни гребцов соревнуются в скорости.'),
  'taizhou/meatball': ('Фрикадельки «Голова льва»', 'Крупные и нежные свиные фрикадельки «голова льва» — классическое блюдо хуайянской кухни.'),
  'jinhua/ham': ('Ветчина Цзиньхуа', 'Эта ветчина, приготовленная по старинному рецепту, считается самой знаменитой в Китае.'),
  'jinhua/film': ('Киностудия Хэньдянь', 'Крупнейшая в мире площадка для съемок под открытым небом, где создается множество исторических сериалов.'),
  'jinhua/cave': ('Пещера Шуанлун', 'В эту подземную пещеру посетители попадают на лодке через узкий проход, что производит незабываемое впечатление.'),
  'jinhua/bridge': ('Древние мосты', 'Арочные каменные мосты и прибрежные городки воплощают в себе изящество региона Цзяннань.'),
  'wuhu/park': ('Парк развлечений Фантэ', 'Один из крупнейших тематических парков Китая, предлагающий семьям множество захватывающих аттракционов.'),
  'wuhu/ironart': ('Железная живопись', 'Изящные картины, выкованные из железа, представляют собой уникальное ремесло с трехсотлетней историей.'),
  'wuhu/rice': ('Рисовый порт', 'Расположенный на берегу Янцзы город исторически был крупнейшим центром торговли рисом в Китае.'),
  'wuhu/river': ('Порт на Янцзы', 'Оживленный речной порт делает этот город главными морскими воротами провинции Аньхой.'),
  'huangshan/peak': ('Хуаншань', 'Гранитные пики, море облаков и причудливые сосны делают эту гору самой знаменитой в Китае.'),
  'huangshan/village': ('Деревня Хунцунь', 'Белостенные деревни в стиле Хуэй с каналами и прудами включены в список ЮНЕСКО и выглядят как ожившие картины.'),
  'huangshan/tea': ('Чай Маофэн', 'Этот зеленый чай с пушистыми почками, собранный на туманных склонах, входит в десятку самых знаменитых чаев Китая.'),
  'huangshan/ink': ('Хуэйская тушь и искусство', 'Хуэйская тушь, резные деревянные дома и каллиграфия являются культурным достоянием этого региона.'),
  'yichun/moon': ('Гора Минъюэ', 'Гора «Яркой луны» славится своими горячими источниками и живописными видами, открывающимися из кабинок канатной дороги.'),
  'yichun/spring': ('Горячие источники', 'Редкие термальные источники, богатые селеном, сделали этот город центром спа-курортов Китая.'),
  'yichun/zen': ('Чань-буддизм', 'Горные храмы, уходящие корнями в китайские школы чань-буддизма, приглашают к умиротворению и покою.'),
  'yichun/rice': ('Рисовая равнина', 'Плодородная равнина Юаньхэ издавна считается главной житницей провинции Цзянси.'),
  'zhangzhou/narcissus': ('Нарцисс', 'Здесь выращивают самые известные в Китае луковицы нарциссов — символ весенних праздников.'),
  'zhangzhou/tulou': ('Тулоу', 'Гигантские круглые крепости из утрамбованной земли включены в список ЮНЕСКО и объединяют под одной крышей целую деревню.'),
  'zhangzhou/banana': ('Тропические фрукты', 'Рощи бананов, лонгана и мандаринов сохраняют тепло дельты зеленым круглый год.'),
  'zhangzhou/coast': ('Остров Дуншань', 'Остров с золотистыми пляжами и рыбацкими деревушками по праву считается жемчужиной южного побережья.'),
  'beijing/great-wall': ('Великая Китайская стена', 'Самое длинное оборонительное сооружение в мире, возводившееся веками для защиты северных границ Китая, а участок Бадалин с его каменными ступенями и сторожевыми башнями является самым посещаемым.'),
  'beijing/temple': ('Храм Неба', 'Священный комплекс, где императоры династий Мин и Цин ежегодно молились о хорошем урожае, а его трехъярусная круглая крыша, построенная без единого гвоздя, является символом китайской архитектуры.'),
  'beijing/pagoda': ('Пагода Тяньнин', 'Эта 57-метровая 13-ярусная кирпичная пагода эпохи Ляо с восьмигранным основанием и искусной резьбой является одним из старейших сооружений Пекина, хранящим память о тысячелетней истории города.'),
  'beijing/opera': ('Пекинская опера', 'Традиционный китайский театр с двухсотлетней историей, сочетающий в себе пение, диалоги, боевые искусства и акробатику, где грим персонажей раскрывает их характер: например, красный цвет символизирует верность, а белый — хитрость.'),
};
